clear
clc
%%
% СОЗДАНИЕ ОБЪЕКТА IF97 (свойства воды и пара)
javaaddpath if97.jar
unitSystem  =  javaMethod('valueOf', 'com.hummeling.if97.IF97$UnitSystem', 'ENGINEERING');
if97  =  com.hummeling.if97.IF97(unitSystem);
%%
%[text] единицы измерения величин:
%[text] ![](text:image:7621)
%%
%[text] ## Исходные данные
%[text] ![](text:image:801b)
t1_in = 310; % температура теплоносителя вход (t'1), °С
t1_out = 282; % температура теплоносителя в выход (t''1), °С
t_pv = 225; % темп-ра питательной воды (tпв), °С
D_pg = 320; % паропроизводительность (Dпг), кг/с
alpha_pr = 0.7; % расход непрерывной продувки (αпр), %
d_n = 16; % наружный диаметр труб ПТО (dн), мм
delta_tr = 1.5; %толщина труб ПТО (δтр), мм
dk_n = 1100; % наружный диаметр стенки коллекторов (dkн), мм
delta_k = 140; % толщина стенки коллекторов (δк), мм
%%
%[text] ## Тепловой расчет ПГ
%[text] ### 2.3.1 Теплофизические характеристики теплоносителя
dt_zap =20; % запас до кипения (Δtзап), °С %[control:slider:79f5]{"position":[9,11]}
t1s = t1_in + dt_zap; % темп-ра насыщения (t1s), °С
p1 = if97.saturationPressureT(t1s); % давление при насыщении(p1), °С
t1_ = (t1_in + t1_out) / 2; % средняя темп-ра (t1_), °С
rho1 = if97.densityPT(p1, t1_); % средняя плотность (ρ1), кг/м^3
mu1 = if97.dynamicViscosityPT(p1, t1_); % дин. вязкость (μ1), Па*с
nu1 = mu1 / rho1; % кин. вязкость (ν1), м^2/с
lambda1 = if97.thermalConductivityPT(p1, t1_)*1e3; % средняя теплопроводность (λ1), Вт/(м*град)
cp1 = if97.isobaricHeatCapacityPT(p1, t1_); % средняя теплоемкость (cp1), кДж/(кг*град)
Pr1 = if97.PrandtlPT(p1, t1_); % число Прандтля

%вывод результата:
run out231.m %[output:793d7201]
%%
%[text] ### 2.3.2 Теплофизические характеристики рабочего тела
deltat = 10; % минимальный температурный напор (δt), °С %[control:slider:144c]{"position":[10,12]}
x2 = 0.998; % степень сухости генерируемого пара %[control:spinner:1dce]{"position":[6,11]}

t2s = t1_out - deltat; % температура насыщения рабочего тела в объеме ПГ (t2s), °С
p2 = if97.saturationPressureT(t2s); %давление рабочего тела (p2), бар
h_pv = if97.specificEnthalpyPT(p2, t_pv); % энтальпия питательной воды на входе в ПГ (hпв), кДж/кг
h_pr = if97.specificEnthalpySaturatedLiquidP(p2); % энтальпия продувочной воды (hпр = h'), кДж/кг
h_out = if97.specificEnthalpySaturatedVapourP(p2); % энтальпия сухого насыщенного пара при давлении p2 (h''2), кДж/кг
h2 = h_out * x2 + h_pr * (1 - x2); % энтальпия осушенного пара на выходе из ПГ (h2), кДж/кг
v2 = if97.specificVolumeSaturatedVapourP(p2) * x2 + if97.specificVolumeSaturatedLiquidP(p2) * (1 - x2); % удельный объём пара на выходе из ПГ (v2), м^3 /кг
rho2 = 1 / v2; % плотность пара на выходе из ПГ (ρ2), кг/м3
rho_pv = if97.densityPT(p2, t_pv); % Плотность питательной воды на входе в ПГ (ρпв), кг/м3

%вывод результата:
run out232.m %[output:4c55dfed]
%%
%[text] ### 2.3.3 Материальный и тепловой балансы ПГ
eta_pg =0.985; % КПД ПГ (ηпг) %[control:slider:5214]{"position":[9,14]}

D_pr = alpha_pr * D_pg / 100; % Величина непрерывной продувки ПГ (Dпр), кг/с
D_pv = D_pg + D_pr; % Расход питательной воды, подаваемой в ПГ (Dпв), кг/с
Q2 = D_pg * (h2 - h_pv) + D_pr * (h_pr - h_pv); % Количество теплоты, получаемое рабочим телом в ПГ (Q2), кВт
Q1 = Q2 / eta_pg; % Количество теплоты, передаваемое теплоносителем в ПГ (Q1), кВт
G1 = Q1 / (cp1 * (t1_in - t1_out)); % Расход теплоносителя через трубную систему поверхности теплообмена ПГ (G1), кг/с

%вывод результата:
run out233.m %[output:2f10ce6c]
%%
%[text] ### 2.3.4. Расчёт коэффициента теплопередачи
R_zagr = 2.5* 1e-5; % Термическое сопротивление загрязнений (Rзагр), 10^-5 м^2*град/Вт %[control:slider:2612]{"position":[10,13]}
mat = "08Х18Н10Т"; %[control:dropdown:7d4a]{"position":[7,18]}
%[text] В качестве материала трубок поверхности теплообмена ПГ АЭС с ВВЭР рекомендуется применять стали аустенитного класса 08Х18Н10Т. 
%[text] ![](text:image:2c3b)
lambda_tr = steelTC(mat, t1_); % Теплопроводность материала трубки ПТО (λтр), Вт/(м*град)
R_tr = delta_tr * 1e-3 / lambda_tr; % Термическое сопротивление стенки трубки (Rтр), (м^2*град)/Вт
w1 = 2.5:0.5:5; % скорость теплоносителя (w1), м/с
Re1 = w1 * (d_n - 2*delta_tr) * 1e-3 / nu1; % Критерий Рейнольдса для теплоносителя
Nu1 = 0.021 * Re1.^0.8 * Pr1^0.43; % Критерий Нуссельта в случае теплообмена при турбулентном течении неметаллических жидкостей и газов в прямых трубах
alpha1 = lambda1 * Nu1 / ((d_n - 2*delta_tr) * 1e-3); % Коэффициент теплоотдачи от теплоносителя к стенке ПТО, Вт/(м2*град)
A = 10.45 / (3.3 - 0.0113 * (t2s - 100)); % к-т А
B = 1./alpha1 + R_zagr + R_tr; % к-т Б
deltat_b = t1_in - t2s;   % Температурный напор на входе теплоносителя (δtб), °С
deltat_m = t1_out - t2s;  % Температурный напор на выходе теплоносителя (δtм), °С
deltat_l = (deltat_b - deltat_m) / log(deltat_b / deltat_m); % Среднелогарифмический температурный напор (δtl), °С

%вывод результата
run out234.m %[output:61f84c24]
%%
if 1==0 % Секция внутри этого условия не будет выполняться при запуске программы, а только по кнопке
%%
  %[control:button:6c4a]{"position":[1,2]}
var2xl(w1, Re1, Nu1, alpha1);
%%
end
%%
%[text] ![](text:image:26ca)
%% РЕШЕНИЕ СИСТЕМЫ УРАВНЕНИЙ п. 2.3.4.10
q_init = 150*1e3; % ввод начального приближения %[control:editfield:79de]{"position":[10,13]}
for i = 1:length(w1) % систему надо решить для каждого значения скорости потока %[output:group:75ce5f78]
    q_in(i)=q_init; % сначала присваивается значение начального приближения
    eps = 1; % погрешность
    j = 1; % счетчик количества итераций
    while eps >= 1e-2 % вычисление завершится, как только погрешность окажется меньше заданного порога
        qq = q_in(i); % необходимо хранить значение из предыдущей итерации
        k_in(i) = 1 / (B(i) + 1 / (A * qq^0.7)); % вычисление kвх
        q_in(i) = k_in(i) * deltat_b; % обновление значения qвх
        eps = abs(q_in(i) - qq) / q_in(i); % вычисление погрешности
        j = j + 1;
    end
    fprintf('w = %.1f м/с: kвх = %.1f Вт/(м2*град), qвх = %.1f кВт/м^2; ε = %.2f%%, итераций - %d\n', w1(i), k_in(i), q_in(i)/1000, eps*100, j) %[output:555cd311]
end %[output:group:75ce5f78]

%% РЕШЕНИЕ СИСТЕМЫ УРАВНЕНИЙ п. 2.3.4.11
for i = 1:length(w1) % систему надо решить для каждого значения скорости потока %[output:group:624a8ddd]
    q_out(i)=q_init; % сначала присваивается значение начального приближения
    eps = 1; % погрешность
    j = 1; % счетчик количества итераций
    while eps >= 1e-2 % вычисление завершится, как только погрешность окажется меньше заданного порога
        qq = q_out(i); % необходимо хранить значение из предыдущей итерации
        k_out(i) = 1 / (B(i) + 1 / (A * qq^0.7)); % вычисление kвых
        q_out(i) = k_out(i) * deltat_m; % обновление значения qвых
        eps = abs(q_out(i) - qq) / q_out(i); % вычисление погрешности
        j = j + 1;
    end
    fprintf('w = %.1f м/с: kвых = %.1f Вт/(м2*град), qвых = %.1f кВт/м^2; ε = %.2f%%, итераций - %d\n', w1(i), k_out(i), q_out(i)/1e3, eps*100, j) %[output:34af2227]
end %[output:group:624a8ddd]
k_ = (k_in + k_out) / 2;
for i=1:length(w1) %[output:group:45b64d04]
    fprintf('w = %.1f м/с: kср = %.2f Вт/(м2*град)\n', w1(i), k_(i)) %[output:27b10ae8]
end %[output:group:45b64d04]
%%
if 1==0 % Секция внутри этого условия не будет выполняться при запуске программы, а только по кнопке
%%
  %[control:button:778d]{"position":[1,2]}
var2xl(w1, k_in, k_out);
%%
end
%%
%[text] ### 2.3.5 Расчет площади поверхности теплообмена
%[text] Фактическая площадь поверхности теплообмена Fф складывается из расчетной величины 
%[text] и запаса на загрязнения и повреждения  труб.
Kzap = 1.07; % Коэффициент запаса поверхности %[control:slider:37a8]{"position":[8,12]}
q_ = k_ * deltat_l; % Плотность теплового потока, усредненная по всей поверхности теплообмена (q_), Вт/м^2
alpha2 = A * q_.^0.7; % Коэффициент теплоотдачи от стенки к рабочему телу (α2), Вт/(м^2*град)
F = Q1 ./ q_ *1e3 ; % Площадь поверхности теплообмена (F), м^2
FF = F * Kzap; % Площадь поверхности теплообмена (Fф), м^2
run out235.m; %[output:768eeae3]
%%
if 1==0 % Секция внутри этого условия не будет выполняться при запуске программы, а только по кнопке
%%
  %[control:button:57ec]{"position":[1,2]}
var2xl(w1, Nu1, Re1, k_, q_, alpha1, alpha2, FF);
%%
end
%%
% создать графики
run out235_g.m %[output:0bbc64a8] %[output:32612785] %[output:0a5c5c39] %[output:10150d9a] %[output:3510018f]
%%
%[text] ## Конструкционный расчет парогенератора
%[text] ### 3.2.1. Определение количества трубок и их рядов
%[text] ![](text:image:9637)
F_n = G1./(rho1 * w1); % площадь проходного сечения всех трубок
d_vn = d_n - 2 * delta_tr; % внутренний диаметр трубки, мм
F1_tr = pi * (d_vn * 1e-3)^2 / 4; % площадь сечения 1 трубки, м^2
n_raw = round(F_n/F1_tr); % число трубок пов-ти теплообмена, шт.
dk_vn = dk_n - 2*delta_k; % Внутренний диаметр коллекторов теплоносителя, мм

run out321_1.m  %[output:45dafa40]
%[text] ![](text:image:3ca2)
S1min = 1.35* d_n; %Горизонтальный шаг по внутренней поверхности коллекторов, мм %[control:slider:2ad5]{"position":[9,13]}
S1 = 1.5* d_n; % Шаг трубок в горизонтальном ряду, мм %[control:slider:3d7e]{"position":[6,9]}
S2 = 1.35* d_n; % Шаг трубок в вертикальном ряду, мм %[control:slider:042a]{"position":[6,10]}
n1_raw = pi * dk_vn / S1min; %  число трубок в горизонтальной плоскости, шт
n1 = round(n1_raw/2)*2; % округление до четного
n2_raw = n_raw/n1; % Число горизонтальных рядов
n2 = round(n2_raw); % округление 
n = n1 * n2; % Уточняем общее число трубок, шт.

run out321_2.m %[output:79298654]
%%
%[text] ### 3.2.2. Определение внутреннего диаметра корпуса ПГ 
%[text] ![](text:image:2d65)
%[text] ![](text:image:91e5)
%[text]  ![](text:image:11e2)
%h2 используется для какой-то энтальпии, поэтому высоты объединены в
%структурку h
h.h2 = round(S2 * (n2 - 1) + d_n); % Высота трубного пучка поверхности теплообмена (h2), мм
h.h1 = 450; % предварительное расстояние от нижней образующей корпуса ПГ до нижнего ряда труб ПТО %[control:slider:9be1]{"position":[8,11]}
h.h3 = 200; % высота от верхнего ряда труб до зеркала испарения (глубина погружения ПТО под зеркало испарения) %[control:slider:7786]{"position":[8,11]}
h.h4 = 600; % высота парового пространства (расстояние от зеркала испарения до низа сепарационных устройств) %[control:slider:4214]{"position":[8,11]}
h.h5 = 400; % расстояние от низа сепарационных устройств до верхней образующей корпуса ПГ %[control:slider:9a06]{"position":[8,11]}
D2 = h.h1 + h.h2 + h.h3 + h.h4 + h.h5; % Внутренний диаметр корпуса по высоте
Z_kor = 3; % количество вертикальных межпакетных коридоров трубного пучка, шт. %[control:spinner:1f0f]{"position":[9,10]}
b_sv1 = 130; % Ширина вертикальных коридоров между пакетами труб, мм %[control:slider:4833]{"position":[9,12]}
b_sv2 = 230; % Ширина свободного пространства между крайними пакетами труб и обечайкой корпуса ПГ, мм %[control:slider:69af]{"position":[9,12]}
B_sv = Z_kor * b_sv1 + 2 * b_sv2; % Суммарное расстояние, не занятое трубной поверхностью в диаметральной плоскости ПГ, мм
D1 = (n1 - 1) * S1 + B_sv; % Диаметр корпуса по ширине, мм
for i = 1:length(w1)
    D(i) = max([D1 D2(i)]); % определение для каждой w1
end
deltaD = abs(D1 - D2) / max([D1 D2]) * 100; % невязка по D, %

run out322_1.m %[output:341ec801]
run out322_2.m %[output:8ad4aa98]
run out322_3.m %[output:45ee7cd9]
%%
%[text] ### 3.2.3. Определение длины трубок ПТО
%[text] ![](text:image:1532)
L_sr = FF ./ (pi * n * (d_n * 1e-3)); % Средняя (расчетная) длина трубок ПТО (Lср), м
R_max = (D - 2 * b_sv2) / 2; % Радиус гиба трубки максимальной длины (Rmax), мм
R_min = b_sv1 / 2; % Радиус гиба трубки минимальной длины (Rmin), мм
R_sr = (R_max + R_min) / 2; % Радиус гиба трубки средней длины (Rср), мм
L_pr = (L_sr - pi * R_sr * 1e-3) / 2; % Длина прямого участка трубок (Lпр), мм
a = 0.25 * D - b_sv2; % длина участка гиба трубок возле коллектора
L_max = 2 * L_pr + pi * R_max * 1e-3 + 2 * a * 1e-3; % Длина самой длинной трубки (Lmax)
L_min = 2 * L_pr + pi * R_min * 1e-3 + 2 * a * 1e-3; % Длина самой короткой трубки (Lmin)

run out323.m %[output:73ed5cea]
%%
%[text] ### 3.2.4. Определение длины корпуса ПГ 
%[text] ![](text:image:572a)
L_ob = 2 * (m2mm(L_pr) + R_max) + dk_n; %  Длина цилиндрической обечайки (Lоб), мм
    L_ob = round(L_ob);
b_dn = 0.2* D; % глубина эллиптического днища корпуса ПГ (bдн), мм %[control:slider:754f]{"position":[8,11]}
    b_dn = round(b_dn);
L = L_ob + 2 * b_dn; % Длина корпуса ПГ без учета толщины стенок (L), мм
S2_k = (D + b_sv1) / 2 - b_sv2; % Поперечный шаг коллекторов (S2k) , мм
    S2_k = round(S2_k);
S1_k = 1.5* dk_n; % Продольный шаг коллекторов (S1k) , мм %[control:slider:33f0]{"position":[8,11]}
L_cob_raw = round(L_ob/3); % Длина центральной обечайки корпуса ПГ
L_cob_min = 2 * (0.9 * dk_n) + S1_k; % минимальная длина центральной обечайки
for i = 1:length(w1) % Если полученное значение LЦ.ОБмин будет больше чем LЦ.ОБ, то значение LЦ.ОБ должно быть скорректировано
    if L_cob_raw(i) < L_cob_min
        L_cob(i) = round(L_cob_min);
    else
        L_cob(i) = round(L_cob(i));
    end
end
L_krob = (L_ob - L_cob) / 2;

run out324.m %[output:0d677bf1]
%%
%[text] 

%[appendix]{"version":"1.0"}
%---
%[metadata:view]
%   data: {"layout":"hidecode","rightPanelPercent":29.3}
